package com.thesystem.service;

import com.thesystem.dto.TitleDTO;
import com.thesystem.entity.Player;
import com.thesystem.entity.PlayerStats;
import com.thesystem.exception.ApiException;
import com.thesystem.repository.PlayerRepository;
import com.thesystem.repository.PlayerStatsRepository;
import com.thesystem.repository.HabitCompletionRepository;
import com.thesystem.repository.HabitRepository;
import com.thesystem.repository.QuestCompletionRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

/**
 * Title system — unlockable Solo-Leveling-style titles the Hunter earns and equips.
 * Titles are derived live from the player's rank, stats, streaks and quest count
 * (no extra table needed); the equipped choice is persisted on the Player.
 */
@Service
public class TitleService {

    private record TitleDef(String key, String name, String description) {}

    private static final List<TitleDef> CATALOG = List.of(
        new TitleDef("AWAKENED",       "The Awakened",    "You answered the System's call."),
        new TitleDef("IRON_WILLED",    "Iron-Willed",     "Forged a 7-day streak. Discipline rising."),
        new TitleDef("RELENTLESS",     "The Relentless",  "A 30-day streak, unbroken. Machine-like."),
        new TitleDef("CODE_HUNTER",    "Code Hunter",     "INT sharpened to 40+. The mind is a weapon."),
        new TitleDef("SHADOW_ATHLETE", "Shadow Athlete",  "STR raised to 40+. The body obeys."),
        new TitleDef("HORMONE_LORD",   "Hormone Lord",    "HOR mastered to 40+. Primal power."),
        new TitleDef("GATE_BREAKER",   "Gate Breaker",    "Cleared 100 total quests."),
        new TitleDef("DECORATED",      "The Decorated",   "Unlocked 5 achievements."),
        new TitleDef("DAWN_HUNTER",    "Dawn Hunter",     "Rose to C-Rank — interview-ready."),
        new TitleDef("ELITE_HUNTER",   "Elite Hunter",    "Reached B-Rank. Among the strong."),
        new TitleDef("SHADOW_MONARCH", "Shadow Monarch",  "S-Rank. The apex. The System bows."),
        // === Habit-mastery titles (Atomic Habits engine) ===
        new TitleDef("THE_CONSISTENT",  "The Consistent",  "Held a habit streak for 21 days."),
        new TitleDef("IRON_DISCIPLINE", "Iron Discipline", "Mastered a habit — 66-day streak."),
        new TitleDef("IDENTITY_SHIFTER","Identity Shifter","Reached 60%+ mastery on 3 habits of the same identity."),
        new TitleDef("KEYSTONE_BEARER", "Keystone Bearer", "Held 3 keystone habits active with 7+ day streaks."),
        new TitleDef("ONE_PERCENT",     "1% Better",       "Completed 100 habit-check-ins — compounding begins."),
        new TitleDef("NEVER_MISS_TWICE","Never Miss Twice","Used the 2-minute rule to save a streak. Discipline over perfection.")
    );

    private final PlayerRepository playerRepository;
    private final PlayerStatsRepository statsRepository;
    private final QuestCompletionRepository completionRepository;
    private final AchievementService achievementService;
    private final PlayerService playerService;
    private final HabitRepository habitRepository;
    private final HabitCompletionRepository habitCompletionRepository;

    public TitleService(PlayerRepository playerRepository,
                        PlayerStatsRepository statsRepository,
                        QuestCompletionRepository completionRepository,
                        AchievementService achievementService,
                        PlayerService playerService,
                        HabitRepository habitRepository,
                        HabitCompletionRepository habitCompletionRepository) {
        this.playerRepository = playerRepository;
        this.statsRepository = statsRepository;
        this.completionRepository = completionRepository;
        this.achievementService = achievementService;
        this.playerService = playerService;
        this.habitRepository = habitRepository;
        this.habitCompletionRepository = habitCompletionRepository;
    }

    public List<TitleDTO> getTitles(Long playerId) {
        Player p = find(playerId);
        PlayerStats s = statsRepository.findByPlayerId(playerId)
                .orElseThrow(() -> new ApiException("Stats not found", HttpStatus.NOT_FOUND));

        int rankIdx = rankIndex(p.getRankLevel());
        int longest = playerService.longestStreak(playerId);
        long totalQuests = completionRepository.countByPlayerId(playerId);
        int achievements = achievementService.getPlayerAchievements(playerId).size();
        String equipped = p.getEquippedTitle();

        List<TitleDTO> out = new ArrayList<>();
        for (TitleDef d : CATALOG) {
            boolean unlocked = isUnlocked(d.key(), rankIdx, longest, totalQuests, achievements, s);
            out.add(new TitleDTO(d.key(), d.name(), d.description(), unlocked, d.key().equals(equipped)));
        }
        return out;
    }

    public List<TitleDTO> equip(Long playerId, String key) {
        Player p = find(playerId);
        TitleDTO match = getTitles(playerId).stream()
                .filter(t -> t.key().equals(key))
                .findFirst()
                .orElseThrow(() -> new ApiException("Title not found: " + key, HttpStatus.NOT_FOUND));
        if (!match.unlocked()) {
            throw new ApiException("Title is still locked", HttpStatus.FORBIDDEN);
        }
        p.setEquippedTitle(key);
        playerRepository.save(p);
        return getTitles(playerId);
    }

    private boolean isUnlocked(String key, int rankIdx, int longest, long totalQuests,
                               int achievements, PlayerStats s) {
        return switch (key) {
            case "AWAKENED"       -> true;
            case "IRON_WILLED"    -> longest >= 7;
            case "RELENTLESS"     -> longest >= 30;
            case "CODE_HUNTER"    -> s.getIntelligence() >= 40;
            case "SHADOW_ATHLETE" -> s.getStrength() >= 40;
            case "HORMONE_LORD"   -> s.getHor() >= 40;
            case "GATE_BREAKER"   -> totalQuests >= 100;
            case "DECORATED"      -> achievements >= 5;
            case "DAWN_HUNTER"    -> rankIdx >= 2; // C-Rank+
            case "ELITE_HUNTER"   -> rankIdx >= 3; // B-Rank+
            case "SHADOW_MONARCH" -> rankIdx >= 5; // S-Rank
            default -> false;
        };
    }

    private int rankIndex(String rank) {
        return switch (rank == null ? "E" : rank) {
            case "D" -> 1; case "C" -> 2; case "B" -> 3; case "A" -> 4; case "S" -> 5;
            default -> 0;
        };
    }

    private Player find(Long playerId) {
        return playerRepository.findById(playerId)
                .orElseThrow(() -> new ApiException("Player not found", HttpStatus.NOT_FOUND));
    }
}

package com.thesystem.service;

import com.thesystem.dto.TitleDTO;
import com.thesystem.entity.Player;
import com.thesystem.entity.PlayerStats;
import com.thesystem.exception.ApiException;
import com.thesystem.repository.PlayerRepository;
import com.thesystem.repository.PlayerStatsRepository;
import com.thesystem.repository.HabitCompletionRepository;
import com.thesystem.repository.HabitRepository;
import com.thesystem.repository.QuestCompletionRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

/**
 * Title system — unlockable Solo-Leveling-style titles the Hunter earns and equips.
 * Titles are derived live from the player's rank, stats, streaks and quest count
 * (no extra table needed); the equipped choice is persisted on the Player.
 */
@Service
public class TitleService {

    private record TitleDef(String key, String name, String description) {}

    private static final List<TitleDef> CATALOG = List.of(
        new TitleDef("AWAKENED",       "The Awakened",    "You answered the System's call."),
        new TitleDef("IRON_WILLED",    "Iron-Willed",     "Forged a 7-day streak. Discipline rising."),
        new TitleDef("RELENTLESS",     "The Relentless",  "A 30-day streak, unbroken. Machine-like."),
        new TitleDef("CODE_HUNTER",    "Code Hunter",     "INT sharpened to 40+. The mind is a weapon."),
        new TitleDef("SHADOW_ATHLETE", "Shadow Athlete",  "STR raised to 40+. The body obeys."),
        new TitleDef("HORMONE_LORD",   "Hormone Lord",    "HOR mastered to 40+. Primal power."),
        new TitleDef("GATE_BREAKER",   "Gate Breaker",    "Cleared 100 total quests."),
        new TitleDef("DECORATED",      "The Decorated",   "Unlocked 5 achievements."),
        new TitleDef("DAWN_HUNTER",    "Dawn Hunter",     "Rose to C-Rank — interview-ready."),
        new TitleDef("ELITE_HUNTER",   "Elite Hunter",    "Reached B-Rank. Among the strong."),
        new TitleDef("SHADOW_MONARCH", "Shadow Monarch",  "S-Rank. The apex. The System bows."),
        // === Habit-mastery titles (Atomic Habits engine) ===
        new TitleDef("THE_CONSISTENT",  "The Consistent",  "Held a habit streak for 21 days."),
        new TitleDef("IRON_DISCIPLINE", "Iron Discipline", "Mastered a habit — 66-day streak."),
        new TitleDef("IDENTITY_SHIFTER","Identity Shifter","Reached 60%+ mastery on 3 habits of the same identity."),
        new TitleDef("KEYSTONE_BEARER", "Keystone Bearer", "Held 3 keystone habits active with 7+ day streaks."),
        new TitleDef("ONE_PERCENT",     "1% Better",       "Completed 100 habit-check-ins — compounding begins."),
        new TitleDef("NEVER_MISS_TWICE","Never Miss Twice","Used the 2-minute rule to save a streak. Discipline over perfection.")
    );

    private final PlayerRepository playerRepository;
    private final PlayerStatsRepository statsRepository;
    private final QuestCompletionRepository completionRepository;
    private final AchievementService achievementService;
    private final PlayerService playerService;
    private final HabitRepository habitRepository;
    private final HabitCompletionRepository habitCompletionRepository;

    public TitleService(PlayerRepository playerRepository,
                        PlayerStatsRepository statsRepository,
                        QuestCompletionRepository completionRepository,
                        AchievementService achievementService,
                        PlayerService playerService,
                        HabitRepository habitRepository,
                        HabitCompletionRepository habitCompletionRepository) {
        this.playerRepository = playerRepository;
        this.statsRepository = statsRepository;
        this.completionRepository = completionRepository;
        this.achievementService = achievementService;
        this.playerService = playerService;
        this.habitRepository = habitRepository;
        this.habitCompletionRepository = habitCompletionRepository;
    }

    public List<TitleDTO> getTitles(Long playerId) {
        Player p = find(playerId);
        PlayerStats s = statsRepository.findByPlayerId(playerId)
                .orElseThrow(() -> new ApiException("Stats not found", HttpStatus.NOT_FOUND));

        int rankIdx = rankIndex(p.getRankLevel());
        int longest = playerService.longestStreak(playerId);
        long totalQuests = completionRepository.countByPlayerId(playerId);
        int achievements = achievementService.getPlayerAchievements(playerId).size();
        String equipped = p.getEquippedTitle();

        // Habit metrics (cheap: one list + set math)
        HabitStats hs = computeHabitStats(playerId);

        List<TitleDTO> out = new ArrayList<>();
        for (TitleDef d : CATALOG) {
            boolean unlocked = isUnlocked(d.key(), rankIdx, longest, totalQuests, achievements, s, hs);
            out.add(new TitleDTO(d.key(), d.name(), d.description(), unlocked, d.key().equals(equipped)));
        }
        return out;
    }

    public List<TitleDTO> equip(Long playerId, String key) {
        Player p = find(playerId);
        TitleDTO match = getTitles(playerId).stream()
                .filter(t -> t.key().equals(key))
                .findFirst()
                .orElseThrow(() -> new ApiException("Title not found: " + key, HttpStatus.NOT_FOUND));
        if (!match.unlocked()) {
            throw new ApiException("Title is still locked", HttpStatus.FORBIDDEN);
        }
        p.setEquippedTitle(key);
        playerRepository.save(p);
        return getTitles(playerId);
    }

    private boolean isUnlocked(String key, int rankIdx, int longest, long totalQuests,
                               int achievements, PlayerStats s) {
        return switch (key) {
            case "AWAKENED"       -> true;
            case "IRON_WILLED"    -> longest >= 7;
            case "RELENTLESS"     -> longest >= 30;
            case "CODE_HUNTER"    -> s.getIntelligence() >= 40;
            case "SHADOW_ATHLETE" -> s.getStrength() >= 40;
            case "HORMONE_LORD"   -> s.getHor() >= 40;
            case "GATE_BREAKER"   -> totalQuests >= 100;
            case "DECORATED"      -> achievements >= 5;
            case "DAWN_HUNTER"    -> rankIdx >= 2; // C-Rank+
            case "ELITE_HUNTER"   -> rankIdx >= 3; // B-Rank+
            case "SHADOW_MONARCH" -> rankIdx >= 5; // S-Rank
            default -> false;
        };
    }

    private int rankIndex(String rank) {
        return switch (rank == null ? "E" : rank) {
            case "D" -> 1; case "C" -> 2; case "B" -> 3; case "A" -> 4; case "S" -> 5;
            default -> 0;
        };
    }

    private Player find(Long playerId) {
        return playerRepository.findById(playerId)
                .orElseThrow(() -> new ApiException("Player not found", HttpStatus.NOT_FOUND));
    }
}

import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  { path: '', pathMatch: 'full', redirectTo: 'system' },
  {
    path: 'login',
    loadComponent: () =>
      import('./features/auth/login.component').then(m => m.LoginComponent),
  },
  {
    path: 'register',
    loadComponent: () =>
      import('./features/auth/register.component').then(m => m.RegisterComponent),
  },
  {
    path: 'system',
    canActivate: [authGuard],
    loadComponent: () =>
      import('./features/system/system.component').then(m => m.SystemComponent),
  },
  {
    path: 'achievements',
    canActivate: [authGuard],
    loadComponent: () =>
      import('./features/achievements/achievements.component').then(m => m.AchievementsComponent),
  },
  { path: '**', redirectTo: 'system' },
];

import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { Capacitor } from '@capacitor/core';
import { LocalNotifications, ScheduleOptions, PermissionStatus, Channel } from '@capacitor/local-notifications';
import { Habit } from '../models/models';

/** The monochrome notification icon used in the Android status bar.
 *  Must match the filename in android/app/src/main/res/drawable/ */
const SMALL_ICON = 'ic_stat_notify';
/** The full-colour app icon shown in the notification drawer (large icon). */
const LARGE_ICON = 'ic_launcher';

@Injectable({ providedIn: 'root' })
export class LocalNotificationsService {
  private router = inject(Router);

  /**
   * ─── Notification channel IDs ───────────────────────────────────────────
   * Android notification channels are IMMUTABLE once created — their sound,
   * importance and vibration can NEVER be changed programmatically afterwards.
   * If we ever need to change a channel's settings we MUST bump its version
   * suffix (v2 → v3 …) so Android treats it as a brand-new channel. Deleting
   * and recreating a channel with the SAME id does NOT reliably reset it
   * (Android may resurrect the old settings), hence the version bump.
   *
   * v3 fixes the "notification shows but is silent" bug: the previous channels
   * were created with `sound: 'default'`, which the Capacitor plugin resolves
   * to `android.resource://<pkg>/raw/default`. That raw resource does not
   * exist, so the channel was created pointing at a missing sound file → total
   * silence. Omitting `sound` lets Android use the real system default sound.
   */
  private static readonly CH = {
    alarms: 'system-alarms-v3',   // URGENT — rings + vibrates (alarms, sleep, midnight)
    game: 'game-events-v3',       // HIGH   — rings + vibrates (HP warnings, level ups)
    reminders: 'reminders-v3',    // DEFAULT — soft nudges (lunch, evening, weekly, habits)
  };

  /** Static IDs */
  private static readonly IDS = {
    midnight: 1,
    wake: 10,
    lunch: 11,
    evening: 12,
    sleep: 13,
    weeklyReview: 14,
    alarm: 500,  // User-set wake alarm (cancelable) — uses 7 slots: 500..506
  };
  private static readonly HABIT_ID_BASE = 2000;
  private static readonly HABIT_ACTION_TYPE = 'HABIT_ACTION';
  private static readonly ACTION_START_NOW = 'start_now';

  private activeTimerId: number | null = null;
  private hpWarningCooldown = false;

  async init(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await this.registerActionTypes();
      this.listenForActions();
    } catch { /* ignore */ }
  }

  async createChannels(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      // Remove every previous channel version so the device stops using the
      // old, broken (silent) channels. New settings only take effect on a
      // freshly-versioned channel id (see the CH doc comment above).
      for (const stale of [
        'system-alarms', 'game-events', 'reminders',            // v1
        'system-alarms-v2', 'game-events-v2', 'reminders-v2',   // v2 (silent bug)
      ]) {
        await LocalNotifications.deleteChannel({ id: stale }).catch(() => {});
      }

      // alarms (v3): URGENT — heads-up + SYSTEM DEFAULT sound + vibration.
      // NOTE: `sound` is intentionally omitted → Android uses the real system
      // default notification sound. Passing a name here would require a matching
      // file in android/app/src/main/res/raw/ or the channel goes SILENT.
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.alarms,
        name: '⚡ THE SYSTEM — Alarms',
        description: 'Wake alarm, sleep reminder and midnight reset notifications',
        importance: 5,       // IMPORTANCE_HIGH → heads-up + sound
        visibility: 1,       // VISIBILITY_PUBLIC → show on lock screen
        vibration: true,
        lights: true,
        lightColor: '#6C63FF',
      });

      // game-events (v3): HIGH — sound + vibration for HP warnings / level ups
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.game,
        name: '◈ THE SYSTEM — Game Events',
        description: 'HP warnings, level ups, dungeon alerts',
        importance: 4,
        visibility: 1,
        vibration: true,
        lights: true,
        lightColor: '#FAC775',
      });

      // reminders (v3): DEFAULT — daily nudges with sound + vibration
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.reminders,
        name: '◈ THE SYSTEM — Reminders',
        description: 'Lunch, evening and weekly review reminders',
        importance: 3,
        visibility: 1,
        vibration: true,
      });
    } catch { /* ignore */ }
  }

  private async registerActionTypes(): Promise<void> {
    try {
      await LocalNotifications.registerActionTypes({
        types: [{
          id: LocalNotificationsService.HABIT_ACTION_TYPE,
          actions: [{ id: LocalNotificationsService.ACTION_START_NOW, title: 'Start Now ⚡', foreground: true }]
        }]
      });
    } catch {}
  }

  private listenForActions(): void {
    LocalNotifications.addListener('localNotificationActionPerformed', (action) => {
      if (action.actionId === LocalNotificationsService.ACTION_START_NOW) {
        this.router.navigate(['/habits']);
      }
    });
  }

  async scheduleAlarms(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: [
          { id: LocalNotificationsService.IDS.midnight },
          { id: LocalNotificationsService.IDS.wake },
          { id: LocalNotificationsService.IDS.sleep }
        ]
      });
      await LocalNotifications.schedule({
        notifications: [
          {
            id: LocalNotificationsService.IDS.midnight,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ SYSTEM ALERT: Midnight Reset',
            body: 'A new day begins. Quests reset. Arise, Hunter.',
            largeBody: '◈ THE SYSTEM HAS RESET ◈\n\nA new day has dawned. All daily quests and routines have been reset.\n\n"The system is not your master, it is your tool. Use it to level up."\n\nPrepare your directives for today.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 0, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.wake,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ WAKE PROTOCOL INITIATED',
            body: 'Cold shower. Sunlight. Eggs. Begin.',
            largeBody: '◈ WAKE PROTOCOL ◈\n\n1. Get out of bed immediately.\n2. Expose your eyes to sunlight.\n3. Take a cold shower.\n4. Consume a high-protein breakfast.\n\nDo not let the system dictate your weakness. Level up today.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 8, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.sleep,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ SLEEP PROTOCOL',
            body: 'Phone down. Sleep before 11:30. System watching.',
            largeBody: '◈ SLEEP PROTOCOL ◈\n\nYour body requires recovery to grow stronger.\n\n1. Put all screens away.\n2. Prepare for sleep.\n3. Sleep before 11:30 PM.\n\nFailure to recover is failure to level up.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 23, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          }
        ]
      });
    } catch {}
  }

  async scheduleReminders(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: [{ id: LocalNotificationsService.IDS.lunch }, { id: LocalNotificationsService.IDS.evening }, { id: LocalNotificationsService.IDS.weeklyReview }]
      });
      await LocalNotifications.schedule({
        notifications: [
          {
            id: LocalNotificationsService.IDS.lunch,
            channelId: 'reminders-v2',
            title: 'FUEL REQUIRED',
            body: 'Proper lunch. No junk. Zinc included.',
            largeBody: '◈ MIDDAY FUEL CHECK ◈\n\nYour body requires clean fuel to maintain peak performance.\n\n◈ No sugar. No processed junk.\n◈ Ensure adequate protein and zinc.\n◈ Hydrate immediately.\n\nDo not poison your avatar.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 13, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.evening,
            channelId: 'reminders-v2',
            title: 'QUESTS REMAINING',
            body: 'Check your incomplete quests. Evening window closing.',
            largeBody: '◈ EVENING DIRECTIVE ◈\n\nThe day is ending, but your tasks are not finished.\n\nCheck the system for incomplete daily quests. Leaving them unfinished will result in penalties.\n\nPush through the fatigue. That is how you level up.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 21, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.weeklyReview,
            channelId: 'reminders-v2',
            title: ' WEEKLY REVIEW',
            body: 'Open the system. Review your week. Set next target.',
            largeBody: '◈ SYSTEM WEEKLY REVIEW ◈\n\nIt is time to assess your growth.\n\n1. Review your completed quests.\n2. Analyze your failed habits.\n3. Adjust your stats allocation.\n4. Set a primary objective for the coming week.\n\nGrowth requires reflection. Open the app now.',
            largeIcon: LARGE_ICON,
            schedule: { on: { weekday: 1, hour: 20, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          }
        ]
      });
    } catch {}
  }

  async cancelAll(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: Object.values(LocalNotificationsService.IDS).map(id => ({ id }))
      });
    } catch {}
  }

  async scheduleAlarm(hour: number, minute: number, label: string, days: boolean[]): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      // Cancel any existing user alarm first
      await LocalNotifications.cancel({ notifications: [{ id: LocalNotificationsService.IDS.alarm }] });

      // We schedule 7 separate daily notifications, one per active day of the week.
      // Weekday: 1=Sunday, 2=Monday, ..., 7=Saturday (Capacitor convention)
      const activeIds: { id: number }[] = [];
      for (let i = 0; i < 7; i++) {
        if (!days[i]) continue;
        const id = LocalNotificationsService.IDS.alarm + i;
        activeIds.push({ id });
        await LocalNotifications.schedule({
          notifications: [{
            id,
            channelId: 'system-alarms-v2',
            title: `⚡ ${label}`,
            body: 'Hunter, your wake alarm is ringing. Arise.',
            largeBody: `◈ ALARM — ${label} ◈\n\nIt is time. The system is watching.\n\n1. Get out of bed immediately.\n2. Execute your morning protocol.\n3. Do not waste this moment.`,
            largeIcon: LARGE_ICON,
            smallIcon: SMALL_ICON,
            schedule: {
              on: { weekday: i + 1, hour, minute },
              allowWhileIdle: true,
              repeats: true,
            },
          }],
        });
      }
    } catch (e) {
      console.error('scheduleAlarm error', e);
    }
  }

  async cancelAlarm(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const ids = Array.from({ length: 7 }, (_, i) => ({ id: LocalNotificationsService.IDS.alarm + i }));
      await LocalNotifications.cancel({ notifications: ids });
    } catch {}
  }

  async scheduleTimer(minutes: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const id = 300 + minutes;
      if (this.activeTimerId !== null) {
        await LocalNotifications.cancel({ notifications: [{ id: this.activeTimerId }] });
      }
      this.activeTimerId = id;
      await LocalNotifications.schedule({
        notifications: [
          {
            id,
            channelId: 'system-alarms-v2',
            title: '✅ FOCUS BLOCK COMPLETE',
            body: `${minutes}-minute session done. Take a break.`,
            largeBody: `Hunter,\n\nYou have successfully completed a ${minutes}-minute focus block.\n\n◈ Consistency is the key to leveling up.\n◈ Your mental stamina has increased.\n\nTake a moment to recover before your next quest.`,
            largeIcon: LARGE_ICON,
            smallIcon: SMALL_ICON,
            schedule: { at: new Date(Date.now() + minutes * 60000), allowWhileIdle: true },
          }
        ]
      });
    } catch {}
  }

  async triggerHpWarning(currentHp: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    if (this.hpWarningCooldown) return;
    this.hpWarningCooldown = true;
    try {
      await LocalNotifications.schedule({
        notifications: [{
          id: 2,
          channelId: 'game-events-v2',
          title: '⚠ CRITICAL: HP BELOW 40',
          body: `HP is at ${currentHp}. Complete quests now or face demotion.`,
          largeBody: `◈ CRITICAL WARNING ◈\n\nYour HP has dropped to a dangerous level (${currentHp} HP).\n\nIf your HP reaches 0, you will face severe penalties and stat reduction.\n\nImmediate Action Required:\n1. Open the system.\n2. Complete pending daily quests.\n3. Restore your health before midnight.\n\nDo not fail.`,
          largeIcon: LARGE_ICON,
          schedule: { at: new Date(Date.now() + 500) },
          smallIcon: SMALL_ICON
        }]
      });
      setTimeout(() => { this.hpWarningCooldown = false; }, 3600000);
    } catch {}
  }

  async triggerGameEvent(title: string, body: string, id: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.schedule({
        notifications: [{
          id,
          channelId: 'game-events-v2',
          title,
          body,
          schedule: { at: new Date(Date.now() + 500) },
          smallIcon: SMALL_ICON
        }]
      });
    } catch {}
  }

  async scheduleHabits(habits: Habit[]): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const existing = await LocalNotifications.getPending();
      const toCancel = existing.notifications
        .filter(n => n.id >= LocalNotificationsService.HABIT_ID_BASE && n.id < LocalNotificationsService.HABIT_ID_BASE + 100000)
        .map(n => ({ id: n.id }));
      if (toCancel.length) await LocalNotifications.cancel({ notifications: toCancel });

      const scheduled = habits
        .filter(h => !h.archived && h.cueTime && h.cueTime.match(/^\d{2}:\d{2}$/))
        .slice(0, 5)
        .map(h => {
          const [hh, mm] = h.cueTime!.split(':').map(n => +n);
          return {
            id: LocalNotificationsService.HABIT_ID_BASE + h.id,
            title: `◈ HABIT CUE — ${h.name}`,
            body: h.cue ? `${h.cue} · Streak: ${h.currentStreak} ` : `Time for your habit. Streak: ${h.currentStreak} `,
            schedule: { on: { hour: hh, minute: mm }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON,
            largeIcon: LARGE_ICON,
            channelId: 'reminders-v2',
            actionTypeId: LocalNotificationsService.HABIT_ACTION_TYPE,
          };
        });
      if (scheduled.length) await LocalNotifications.schedule({ notifications: scheduled });
    } catch {}
  }
}

import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { Capacitor } from '@capacitor/core';
import { LocalNotifications, ScheduleOptions, PermissionStatus, Channel } from '@capacitor/local-notifications';
import { Habit } from '../models/models';

/** The monochrome notification icon used in the Android status bar.
 *  Must match the filename in android/app/src/main/res/drawable/ */
const SMALL_ICON = 'ic_stat_notify';
/** The full-colour app icon shown in the notification drawer (large icon). */
const LARGE_ICON = 'ic_launcher';

@Injectable({ providedIn: 'root' })
export class LocalNotificationsService {
  private router = inject(Router);

  /**
   * ─── Notification channel IDs ───────────────────────────────────────────
   * Android notification channels are IMMUTABLE once created — their sound,
   * importance and vibration can NEVER be changed programmatically afterwards.
   * If we ever need to change a channel's settings we MUST bump its version
   * suffix (v2 → v3 …) so Android treats it as a brand-new channel. Deleting
   * and recreating a channel with the SAME id does NOT reliably reset it
   * (Android may resurrect the old settings), hence the version bump.
   *
   * v3 fixes the "notification shows but is silent" bug: the previous channels
   * were created with `sound: 'default'`, which the Capacitor plugin resolves
   * to `android.resource://<pkg>/raw/default`. That raw resource does not
   * exist, so the channel was created pointing at a missing sound file → total
   * silence. Omitting `sound` lets Android use the real system default sound.
   */
  private static readonly CH = {
    alarms: 'system-alarms-v3',   // URGENT — rings + vibrates (alarms, sleep, midnight)
    game: 'game-events-v3',       // HIGH   — rings + vibrates (HP warnings, level ups)
    reminders: 'reminders-v3',    // DEFAULT — soft nudges (lunch, evening, weekly, habits)
  };

  /** Static IDs */
  private static readonly IDS = {
    midnight: 1,
    wake: 10,
    lunch: 11,
    evening: 12,
    sleep: 13,
    weeklyReview: 14,
    alarm: 500,  // User-set wake alarm (cancelable) — uses 7 slots: 500..506
  };
  private static readonly HABIT_ID_BASE = 2000;
  private static readonly HABIT_ACTION_TYPE = 'HABIT_ACTION';
  private static readonly ACTION_START_NOW = 'start_now';

  private activeTimerId: number | null = null;
  private hpWarningCooldown = false;

  async init(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await this.registerActionTypes();
      this.listenForActions();
    } catch { /* ignore */ }
  }

  async createChannels(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      // Remove every previous channel version so the device stops using the
      // old, broken (silent) channels. New settings only take effect on a
      // freshly-versioned channel id (see the CH doc comment above).
      for (const stale of [
        'system-alarms', 'game-events', 'reminders',            // v1
        'system-alarms-v2', 'game-events-v2', 'reminders-v2',   // v2 (silent bug)
      ]) {
        await LocalNotifications.deleteChannel({ id: stale }).catch(() => {});
      }

      // alarms (v3): URGENT — heads-up + SYSTEM DEFAULT sound + vibration.
      // NOTE: `sound` is intentionally omitted → Android uses the real system
      // default notification sound. Passing a name here would require a matching
      // file in android/app/src/main/res/raw/ or the channel goes SILENT.
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.alarms,
        name: '⚡ THE SYSTEM — Alarms',
        description: 'Wake alarm, sleep reminder and midnight reset notifications',
        importance: 5,       // IMPORTANCE_HIGH → heads-up + sound
        visibility: 1,       // VISIBILITY_PUBLIC → show on lock screen
        vibration: true,
        lights: true,
        lightColor: '#6C63FF',
      });

      // game-events (v3): HIGH — sound + vibration for HP warnings / level ups
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.game,
        name: '◈ THE SYSTEM — Game Events',
        description: 'HP warnings, level ups, dungeon alerts',
        importance: 4,
        visibility: 1,
        vibration: true,
        lights: true,
        lightColor: '#FAC775',
      });

      // reminders (v3): DEFAULT — daily nudges with sound + vibration
      await LocalNotifications.createChannel({
        id: LocalNotificationsService.CH.reminders,
        name: '◈ THE SYSTEM — Reminders',
        description: 'Lunch, evening and weekly review reminders',
        importance: 3,
        visibility: 1,
        vibration: true,
      });
    } catch { /* ignore */ }
  }

  private async registerActionTypes(): Promise<void> {
    try {
      await LocalNotifications.registerActionTypes({
        types: [{
          id: LocalNotificationsService.HABIT_ACTION_TYPE,
          actions: [{ id: LocalNotificationsService.ACTION_START_NOW, title: 'Start Now ⚡', foreground: true }]
        }]
      });
    } catch {}
  }

  private listenForActions(): void {
    LocalNotifications.addListener('localNotificationActionPerformed', (action) => {
      if (action.actionId === LocalNotificationsService.ACTION_START_NOW) {
        this.router.navigate(['/habits']);
      }
    });
  }

  async scheduleAlarms(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: [
          { id: LocalNotificationsService.IDS.midnight },
          { id: LocalNotificationsService.IDS.wake },
          { id: LocalNotificationsService.IDS.sleep }
        ]
      });
      await LocalNotifications.schedule({
        notifications: [
          {
            id: LocalNotificationsService.IDS.midnight,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ SYSTEM ALERT: Midnight Reset',
            body: 'A new day begins. Quests reset. Arise, Hunter.',
            largeBody: '◈ THE SYSTEM HAS RESET ◈\n\nA new day has dawned. All daily quests and routines have been reset.\n\n"The system is not your master, it is your tool. Use it to level up."\n\nPrepare your directives for today.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 0, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.wake,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ WAKE PROTOCOL INITIATED',
            body: 'Cold shower. Sunlight. Eggs. Begin.',
            largeBody: '◈ WAKE PROTOCOL ◈\n\n1. Get out of bed immediately.\n2. Expose your eyes to sunlight.\n3. Take a cold shower.\n4. Consume a high-protein breakfast.\n\nDo not let the system dictate your weakness. Level up today.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 8, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.sleep,
            channelId: LocalNotificationsService.CH.alarms,
            title: '⚡ SLEEP PROTOCOL',
            body: 'Phone down. Sleep before 11:30. System watching.',
            largeBody: '◈ SLEEP PROTOCOL ◈\n\nYour body requires recovery to grow stronger.\n\n1. Put all screens away.\n2. Prepare for sleep.\n3. Sleep before 11:30 PM.\n\nFailure to recover is failure to level up.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 23, minute: 0 }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON
          }
        ]
      });
    } catch {}
  }

  async scheduleReminders(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: [{ id: LocalNotificationsService.IDS.lunch }, { id: LocalNotificationsService.IDS.evening }, { id: LocalNotificationsService.IDS.weeklyReview }]
      });
      await LocalNotifications.schedule({
        notifications: [
          {
            id: LocalNotificationsService.IDS.lunch,
            channelId: LocalNotificationsService.CH.reminders,
            title: 'FUEL REQUIRED',
            body: 'Proper lunch. No junk. Zinc included.',
            largeBody: '◈ MIDDAY FUEL CHECK ◈\n\nYour body requires clean fuel to maintain peak performance.\n\n◈ No sugar. No processed junk.\n◈ Ensure adequate protein and zinc.\n◈ Hydrate immediately.\n\nDo not poison your avatar.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 13, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.evening,
            channelId: 'reminders-v2',
            title: 'QUESTS REMAINING',
            body: 'Check your incomplete quests. Evening window closing.',
            largeBody: '◈ EVENING DIRECTIVE ◈\n\nThe day is ending, but your tasks are not finished.\n\nCheck the system for incomplete daily quests. Leaving them unfinished will result in penalties.\n\nPush through the fatigue. That is how you level up.',
            largeIcon: LARGE_ICON,
            schedule: { on: { hour: 21, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          },
          {
            id: LocalNotificationsService.IDS.weeklyReview,
            channelId: 'reminders-v2',
            title: ' WEEKLY REVIEW',
            body: 'Open the system. Review your week. Set next target.',
            largeBody: '◈ SYSTEM WEEKLY REVIEW ◈\n\nIt is time to assess your growth.\n\n1. Review your completed quests.\n2. Analyze your failed habits.\n3. Adjust your stats allocation.\n4. Set a primary objective for the coming week.\n\nGrowth requires reflection. Open the app now.',
            largeIcon: LARGE_ICON,
            schedule: { on: { weekday: 1, hour: 20, minute: 0 }, repeats: true },
            smallIcon: SMALL_ICON
          }
        ]
      });
    } catch {}
  }

  async cancelAll(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.cancel({
        notifications: Object.values(LocalNotificationsService.IDS).map(id => ({ id }))
      });
    } catch {}
  }

  async scheduleAlarm(hour: number, minute: number, label: string, days: boolean[]): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      // Cancel any existing user alarm first
      await LocalNotifications.cancel({ notifications: [{ id: LocalNotificationsService.IDS.alarm }] });

      // We schedule 7 separate daily notifications, one per active day of the week.
      // Weekday: 1=Sunday, 2=Monday, ..., 7=Saturday (Capacitor convention)
      const activeIds: { id: number }[] = [];
      for (let i = 0; i < 7; i++) {
        if (!days[i]) continue;
        const id = LocalNotificationsService.IDS.alarm + i;
        activeIds.push({ id });
        await LocalNotifications.schedule({
          notifications: [{
            id,
            channelId: 'system-alarms-v2',
            title: `⚡ ${label}`,
            body: 'Hunter, your wake alarm is ringing. Arise.',
            largeBody: `◈ ALARM — ${label} ◈\n\nIt is time. The system is watching.\n\n1. Get out of bed immediately.\n2. Execute your morning protocol.\n3. Do not waste this moment.`,
            largeIcon: LARGE_ICON,
            smallIcon: SMALL_ICON,
            schedule: {
              on: { weekday: i + 1, hour, minute },
              allowWhileIdle: true,
              repeats: true,
            },
          }],
        });
      }
    } catch (e) {
      console.error('scheduleAlarm error', e);
    }
  }

  async cancelAlarm(): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const ids = Array.from({ length: 7 }, (_, i) => ({ id: LocalNotificationsService.IDS.alarm + i }));
      await LocalNotifications.cancel({ notifications: ids });
    } catch {}
  }

  async scheduleTimer(minutes: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const id = 300 + minutes;
      if (this.activeTimerId !== null) {
        await LocalNotifications.cancel({ notifications: [{ id: this.activeTimerId }] });
      }
      this.activeTimerId = id;
      await LocalNotifications.schedule({
        notifications: [
          {
            id,
            channelId: 'system-alarms-v2',
            title: '✅ FOCUS BLOCK COMPLETE',
            body: `${minutes}-minute session done. Take a break.`,
            largeBody: `Hunter,\n\nYou have successfully completed a ${minutes}-minute focus block.\n\n◈ Consistency is the key to leveling up.\n◈ Your mental stamina has increased.\n\nTake a moment to recover before your next quest.`,
            largeIcon: LARGE_ICON,
            smallIcon: SMALL_ICON,
            schedule: { at: new Date(Date.now() + minutes * 60000), allowWhileIdle: true },
          }
        ]
      });
    } catch {}
  }

  async triggerHpWarning(currentHp: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    if (this.hpWarningCooldown) return;
    this.hpWarningCooldown = true;
    try {
      await LocalNotifications.schedule({
        notifications: [{
          id: 2,
          channelId: 'game-events-v2',
          title: '⚠ CRITICAL: HP BELOW 40',
          body: `HP is at ${currentHp}. Complete quests now or face demotion.`,
          largeBody: `◈ CRITICAL WARNING ◈\n\nYour HP has dropped to a dangerous level (${currentHp} HP).\n\nIf your HP reaches 0, you will face severe penalties and stat reduction.\n\nImmediate Action Required:\n1. Open the system.\n2. Complete pending daily quests.\n3. Restore your health before midnight.\n\nDo not fail.`,
          largeIcon: LARGE_ICON,
          schedule: { at: new Date(Date.now() + 500) },
          smallIcon: SMALL_ICON
        }]
      });
      setTimeout(() => { this.hpWarningCooldown = false; }, 3600000);
    } catch {}
  }

  async triggerGameEvent(title: string, body: string, id: number): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      await LocalNotifications.schedule({
        notifications: [{
          id,
          channelId: 'game-events-v2',
          title,
          body,
          schedule: { at: new Date(Date.now() + 500) },
          smallIcon: SMALL_ICON
        }]
      });
    } catch {}
  }

  async scheduleHabits(habits: Habit[]): Promise<void> {
    if (!Capacitor.isNativePlatform()) return;
    try {
      const existing = await LocalNotifications.getPending();
      const toCancel = existing.notifications
        .filter(n => n.id >= LocalNotificationsService.HABIT_ID_BASE && n.id < LocalNotificationsService.HABIT_ID_BASE + 100000)
        .map(n => ({ id: n.id }));
      if (toCancel.length) await LocalNotifications.cancel({ notifications: toCancel });

      const scheduled = habits
        .filter(h => !h.archived && h.cueTime && h.cueTime.match(/^\d{2}:\d{2}$/))
        .slice(0, 5)
        .map(h => {
          const [hh, mm] = h.cueTime!.split(':').map(n => +n);
          return {
            id: LocalNotificationsService.HABIT_ID_BASE + h.id,
            title: `◈ HABIT CUE — ${h.name}`,
            body: h.cue ? `${h.cue} · Streak: ${h.currentStreak} ` : `Time for your habit. Streak: ${h.currentStreak} `,
            schedule: { on: { hour: hh, minute: mm }, allowWhileIdle: true, repeats: true },
            smallIcon: SMALL_ICON,
            largeIcon: LARGE_ICON,
            channelId: 'reminders-v2',
            actionTypeId: LocalNotificationsService.HABIT_ACTION_TYPE,
          };
        });
      if (scheduled.length) await LocalNotifications.schedule({ notifications: scheduled });
    } catch {}
  }
}

/* ============================================================
   THE SYSTEM — Solo Leveling Life OS · Premium 3D Theme v4
   Foundation: design tokens + container queries + spacing scale.
   ============================================================ */
@use '@angular/material' as mat;
@import '@angular/cdk/overlay-prebuilt.css';

/* ── Google Fonts ─────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Rajdhani:wght@400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap');

:root {
  /* ── Backgrounds ────────────────────────────────────────── */
  --bg-primary:   #05050d;
  --bg-secondary: #0a0a18;
  --card-bg:      #10101e;
  --border:       #1c1c34;
  --border-glow:  #2b2b52;

  /* ── Accents ────────────────────────────────────────────── */
  --accent-purple:     #6C63FF;
  --accent-purple-2:   #534AB7;
  --accent-purple-dim: rgba(108,99,255,0.18);
  --accent-teal:   #1FBE8E;
  --accent-gold:   #FAC775;
  --accent-red:    #E24B4A;
  --accent-cyan:   #4fc3f7;

  /* ── Text ───────────────────────────────────────────────── */
  --text-primary:   #EEF3FA;
  --text-secondary: #7a8494;
  --text-dim:       #3a4050;

  /* ── Stat colors ────────────────────────────────────────── */
  --stat-str: #FF6B3D;
  --stat-int: #6C63FF;
  --stat-vit: #1FBE8E;
  --stat-agi: #FFB020;
  --stat-per: #3B9BFF;
  --stat-hor: #FF5252;

  --system-blue: #4fc3f7;
  --system-glow: rgba(108,99,255,0.60);

  /* ── HP colors ──────────────────────────────────────────── */
  --hp-high: #1FBE8E;
  --hp-mid:  #FAC775;
  --hp-low:  #E24B4A;

  /* ── Spacing scale ──────────────────────────────────────── */
  --s-1:  4px;
  --s-2:  8px;
  --s-3: 12px;
  --s-4: 16px;
  --s-5: 20px;
  --s-6: 24px;
  --s-8: 32px;
  --s-10: 40px;

  /* ── Mobile navigation ──────────────────────────────────── */
  /* Bottom nav bar height + safe-area-inset-bottom */
  --bottom-nav-height: 70px;
  --bottom-nav-total: calc(var(--bottom-nav-height) + env(safe-area-inset-bottom, 0px));

  /* ── Border radius scale ────────────────────────────────── */
  --r-sm:   6px;
  --r-md:  10px;
  --r-lg:  16px;
  --r-xl:  20px;
  --r-pill: 999px;

  /* ── Typography scale ───────────────────────────────────── */
  --fs-2xs: 0.5rem;
  --fs-xs:  0.62rem;
  --fs-sm:  0.72rem;
  --fs-md:  0.86rem;
  --fs-lg:  1rem;
  --fs-xl:  1.2rem;

  /* ── 3D depth / elevation tokens ───────────────────────── */
  --elev-1:
    0 1px 2px rgba(0,0,0,0.40),
    0 2px 8px rgba(0,0,0,0.35);
  --elev-2:
    0 2px 4px rgba(0,0,0,0.45),
    0 8px 20px rgba(0,0,0,0.45),
    0 0 0 1px rgba(255,255,255,0.02) inset;
  --elev-3:
    0 4px 8px rgba(0,0,0,0.50),
    0 16px 40px rgba(0,0,0,0.55),
    0 0 32px rgba(108,99,255,0.10),
    0 1px 0 rgba(255,255,255,0.05) inset;
  --elev-float:
    0 24px 60px rgba(0,0,0,0.60),
    0 8px 24px rgba(108,99,255,0.22),
    0 1px 0 rgba(255,255,255,0.07) inset;

  /* ── Glass surface ──────────────────────────────────────── */
  --glass-fill: linear-gradient(160deg, rgba(24,24,44,0.72), rgba(12,12,26,0.78));
  --glass-blur: 16px;

  /* ── Motion ─────────────────────────────────────────────── */
  --ease-spring: cubic-bezier(.22,1,.36,1);
  --duration-fast:   150ms;
  --duration-normal: 280ms;
  --duration-slow:   420ms;
}

* { box-sizing: border-box; }
html, body { height: 100%; margin: 0; padding: 0; }

/* Enable GPU-accelerated 3D across the app — perspective on html causes
   backdrop-filter blur artefacts on nested elements, so we apply it only
   per-element where needed (see .card-3d hover in styles below). */
/* html { perspective: 1400px; } ← intentionally removed */

/* ── Mobile-first responsive foundations ─────────────────────── */
html {
  font-size: clamp(14px, 1.5vw + 10px, 16px);
  -webkit-text-size-adjust: 100%;
  text-size-adjust: 100%;
}

/* ── Touch targets — only on primary interactive elements ──── */
/* Avoids forcing 44px on tiny UI micro-buttons (handled per-component) */
a[href], [role='button']:not([class*="mini"]):not([class*="tog"]):not([class*="gear"]):not([class*="cls"]) {
  min-height: 44px;
  min-width: 44px;
  touch-action: manipulation;
}
button { touch-action: manipulation; }
.nav a { min-width: unset; min-height: unset; padding: 8px 6px; }

body {
  background:
    radial-gradient(ellipse 1400px 720px at 28% -8%,  rgba(108,99,255,0.24), transparent 60%),
    radial-gradient(ellipse 1100px 620px at 82% 112%, rgba(31,190,142,0.14), transparent 55%),
    radial-gradient(ellipse 640px 440px at 96% 4%,    rgba(79,195,247,0.10), transparent 50%),
    var(--bg-primary);
  color: var(--text-primary);
  font-family: 'Inter', sans-serif;
  min-height: 100vh;
  overflow-x: hidden;
}

/* ── Animated aurora / nebula layer (adds living depth) ──────── */
body::before {
  content: '';
  position: fixed;
  inset: -20%;
  background:
    radial-gradient(closest-side, rgba(108,99,255,0.16), transparent 70%) 20% 30% / 55% 55% no-repeat,
    radial-gradient(closest-side, rgba(31,190,142,0.12), transparent 70%) 80% 70% / 50% 50% no-repeat,
    radial-gradient(closest-side, rgba(79,195,247,0.10), transparent 70%) 60% 15% / 45% 45% no-repeat;
  filter: blur(30px);
  pointer-events: none;
  z-index: 0;
  animation: aurora 26s ease-in-out infinite alternate;
}

@keyframes aurora {
  0%   { transform: translate3d(0,0,0) scale(1);        opacity: .85; }
  50%  { transform: translate3d(3%, -2%, 0) scale(1.08); opacity: 1; }
  100% { transform: translate3d(-2%, 2%, 0) scale(1.04); opacity: .8; }
}

/* ── Star / particle field ───────────────────────────────────── */
body::after {
  content: '';
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(1px 1px at 8%  15%, rgba(255,255,255,0.50), transparent),
    radial-gradient(1px 1px at 22% 55%, rgba(79,195,247,0.45), transparent),
    radial-gradient(1px 1px at 38% 28%, rgba(255,255,255,0.30), transparent),
    radial-gradient(1px 1px at 55% 72%, rgba(108,99,255,0.50), transparent),
    radial-gradient(1px 1px at 72% 42%, rgba(255,255,255,0.35), transparent),
    radial-gradient(2px 2px at 85% 18%, rgba(250,199,117,0.30), transparent),
    radial-gradient(1px 1px at 93% 78%, rgba(31,190,142,0.40), transparent),
    radial-gradient(1px 1px at 15% 88%, rgba(255,255,255,0.25), transparent),
    radial-gradient(1px 1px at 64% 8%,  rgba(79,195,247,0.30), transparent),
    radial-gradient(2px 2px at 48% 96%, rgba(108,99,255,0.25), transparent);
  background-size: 600px 600px;
  opacity: 0.55;
  pointer-events: none;
  z-index: 0;
  animation: drift 80s linear infinite;
}

@keyframes drift {
  from { background-position: 0 0; }
  to   { background-position: 600px 600px; }
}

/* ── Typography ───────────────────────────────────────────── */
.mono  { font-family: 'Orbitron', 'Courier New', monospace; }
.tech  { font-family: 'Rajdhani', sans-serif; letter-spacing: .5px; }

/* Shared desktop top navigation. Several feature pages own their headers, so
   keep the base nav behavior global and let pages only tune colors/spacing. */
.topbar .nav,
.topbar .desktop-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: clamp(12px, 1.4vw, 20px);
  flex-wrap: wrap;
}
.topbar .nav a,
.topbar .desktop-nav a,
.bottom-nav a {
  white-space: nowrap;
  word-break: normal;
  overflow-wrap: normal;
  text-decoration: none;
}
.topbar .nav a {
  color: var(--text-secondary);
  font-size: clamp(.62rem, .78vw, .76rem);
  letter-spacing: 2px;
  font-weight: 700;
}
.topbar .nav a:hover,
.topbar .nav a.active {
  color: var(--text-primary);
}

/* ── Scrollbar ─────────────────────────────────────────────── */
::-webkit-scrollbar { width: 9px; height: 9px; }
::-webkit-scrollbar-track { background: var(--bg-secondary); }
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, #6C63FF, #2a2670);
  border-radius: 6px;
  border: 2px solid var(--bg-secondary);
}
::-webkit-scrollbar-thumb:hover { background: linear-gradient(180deg, #8b83ff, #3a34a0); }

/* ============================================================
   3D SYSTEM CARD — glassmorphic surface with real depth
   container-type: inline-size enables @container queries in
   child components so they adapt to the card's own width, not
   the viewport — this is the key to rock-solid responsive UX.
   ============================================================ */
.system-card {
  background: var(--glass-fill);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  position: relative;
  padding: clamp(var(--s-3), 3vw, var(--s-5));
  backdrop-filter: blur(var(--glass-blur));
  -webkit-backdrop-filter: blur(var(--glass-blur));
  box-shadow: var(--elev-2);
  /* Container query foundation — child CSS can use @container */
  container-type: inline-size;
  container-name: card;
  transition:
    transform  var(--duration-normal) var(--ease-spring),
    box-shadow var(--duration-normal) var(--ease-spring),
    border-color var(--duration-fast);
}
/* Gradient rim-light border */
.system-card::after {
  content: '';
  position: absolute; inset: 0;
  border-radius: var(--r-xl);
  padding: 1px;
  background: linear-gradient(135deg, rgba(108,99,255,0.65), transparent 40%, rgba(79,195,247,0.35));
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}
/* Top specular highlight */
.system-card::before {
  content: '';
  position: absolute; inset: 0 0 auto 0;
  height: 42%;
  border-radius: var(--r-xl) var(--r-xl) 40% 40% / var(--r-xl) var(--r-xl) 100% 100%;
  background: linear-gradient(180deg, rgba(255,255,255,0.06), transparent);
  pointer-events: none;
}
.system-card:hover {
  border-color: rgba(108,99,255,0.45);
  box-shadow: var(--elev-3);
  transform: translateY(-2px);
}

/* Opt-in interactive 3D tilt/lift */
.card-3d {
  transition: transform .35s var(--ease-spring), box-shadow .35s var(--ease-spring);
  will-change: transform;
}
.card-3d:hover {
  transform: perspective(900px) rotateX(2deg) rotateY(-2deg) translateY(-3px) scale(1.01);
  box-shadow: var(--elev-float);
}
.card-3d:active { transform: perspective(900px) translateY(-1px) scale(.997); }

/* ── Premium 3D buttons ──────────────────────────────────────
   Use class="btn-3d" for primary actions. */
.btn-3d {
  position: relative;
  border: 1px solid rgba(108,99,255,0.45);
  border-radius: 12px;
  background: linear-gradient(180deg, #6C63FF, #4a42b0);
  color: #fff;
  font-family: 'Rajdhani', sans-serif;
  font-weight: 700;
  letter-spacing: 1.5px;
  cursor: pointer;
  box-shadow:
    0 6px 0 #322b7a,
    0 10px 22px rgba(108,99,255,0.40),
    0 1px 0 rgba(255,255,255,0.30) inset;
  transition: transform .12s ease, box-shadow .12s ease, filter .2s;
}
.btn-3d:hover { filter: brightness(1.08); }
.btn-3d:active {
  transform: translateY(4px);
  box-shadow:
    0 2px 0 #322b7a,
    0 4px 10px rgba(108,99,255,0.35),
    0 1px 0 rgba(255,255,255,0.25) inset;
}

/* ── Glow utilities ───────────────────────────────────────── */
.glow-text  { text-shadow: 0 0 18px var(--system-glow), 0 0 36px var(--system-glow); }
.glow-teal  { text-shadow: 0 0 12px rgba(31,190,142,0.8); }
.glow-gold  { text-shadow: 0 0 12px rgba(250,199,117,0.7); }

/* XP/progress shimmer utility */
@keyframes shimmer {
  0%,60% { transform: translateX(-100%); }
  100%   { transform: translateX(300%); }
}

/* ── Angular Material dark theme ──────────────────────────── */
$sys-primary: mat.define-palette(mat.$indigo-palette, 400);
$sys-accent:  mat.define-palette(mat.$teal-palette,   400);
$sys-warn:    mat.define-palette(mat.$red-palette);
$sys-theme: mat.define-dark-theme((
  color: (primary: $sys-primary, accent: $sys-accent, warn: $sys-warn),
  typography: mat.define-typography-config(),
  density: 0,
));
@include mat.core();
@include mat.all-component-themes($sys-theme);

/* ── System Snackbar ──────────────────────────────────────── */
@keyframes systemSnackPulse {
  0% { box-shadow: 0 0 15px rgba(31,190,142,0.6), inset 0 0 10px rgba(31,190,142,0.2); border-color: rgba(31,190,142, 0.8); }
  50% { box-shadow: 0 0 35px rgba(31,190,142,0.9), inset 0 0 20px rgba(31,190,142,0.4); border-color: rgba(31,190,142, 1); }
  100% { box-shadow: 0 0 15px rgba(31,190,142,0.6), inset 0 0 10px rgba(31,190,142,0.2); border-color: rgba(31,190,142, 0.8); }
}

.mat-mdc-snack-bar-container.system-snack {
  --mdc-snackbar-container-color:       rgba(10, 10, 24, 0.95);
  --mdc-snackbar-supporting-text-color: #EEF3FA;
  --mat-snack-bar-button-color:         #FAC775;
}
.mat-mdc-snack-bar-container.system-snack .mdc-snackbar__surface {
  border: 1px solid var(--accent-teal);
  border-radius: 12px;
  background: linear-gradient(135deg, rgba(10, 10, 24, 0.95), rgba(31, 190, 142, 0.15));
  backdrop-filter: blur(10px);
  animation: systemSnackPulse 2s infinite ease-in-out;
  font-family: 'Orbitron', sans-serif;
  letter-spacing: 1px;
}
.mat-mdc-snack-bar-container.system-snack-warn .mdc-snackbar__surface {
  border: 1px solid #E24B4A;
  background: linear-gradient(135deg, rgba(10, 10, 24, 0.95), rgba(226, 75, 74, 0.15));
  box-shadow: 0 0 28px rgba(226,75,74,0.65), inset 0 0 12px rgba(226,75,74,0.2);
  font-family: 'Orbitron', sans-serif;
}

/* ── Overlay backdrop ─────────────────────────────────────── */
.cdk-overlay-dark-backdrop {
  background: rgba(3,3,10,0.92);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}
/* Ensure the CDK overlay sits above the bottom navigation bar on mobile */
.cdk-overlay-container {
  z-index: 1000;
}

/* ── Holographic flicker animation ──────────────────────────── */
@keyframes holoBlink {
  0%,100% { opacity: 1; }
  92%     { opacity: 1; }
  93%     { opacity: 0.7; }
  94%     { opacity: 1; }
  96%     { opacity: 0.85; }
  97%     { opacity: 1; }
}

/* ── Stat increase pop ─────────────────────────────────────── */
@keyframes statPop {
  0%   { transform: scale(1); }
  40%  { transform: scale(1.22); filter: brightness(1.8); }
  70%  { transform: scale(0.96); }
  100% { transform: scale(1); filter: brightness(1); }
}
.stat-pop { animation: statPop .55s var(--ease-spring) both; }

/* ── HP danger pulse ─────────────────────────────────────────── */
@keyframes dangerPulse {
  0%,100% { box-shadow: 0 0 8px rgba(226,75,74,0.4); }
  50%     { box-shadow: 0 0 28px rgba(226,75,74,0.9); }
}
.hp-danger { animation: dangerPulse 1.6s ease-in-out infinite; }

/* ── Level-up dialog — full-screen centered overlay ─────────── */
/* The CDK overlay container is already position:fixed full-screen.
   We just need to ensure our custom panel class strips Material's
   padding and that the surface is transparent so our card shows. */
.level-up-panel {
  /* Override Material's default max-width on mobile */
  max-width: calc(100vw - 24px) !important;
}
.level-up-panel .mat-mdc-dialog-container {
  background: transparent;
  box-shadow: none;
  /* Ensure container doesn't add its own padding that shifts alignment */
  padding: 0;
}
.level-up-panel .mat-mdc-dialog-surface {
  background: transparent !important;
  box-shadow: none !important;
  overflow: visible;
  padding: 0;
}
/* The CDK overlay pane that wraps the dialog — make sure it's centred */
.cdk-overlay-pane:has(.level-up-panel),
.cdk-global-overlay-wrapper:has(.level-up-panel) {
  display: flex;
  align-items: center;
  justify-content: center;
}

/* ── Android 15 / iOS edge-to-edge safe areas ───────────────── */
/* Applied universally — env() returns 0 on desktop so no visual change there */
.route-host {
  min-height: 100dvh;
}
@media (max-width: 760px) {
  .route-host {
    /* Reserve space at bottom for the fixed bottom nav + device home indicator */
    padding-bottom: var(--bottom-nav-total);
  }
}
/* Extra side/top safe areas only needed on real devices */
body.native-platform .route-host {
  padding-left:  max(env(safe-area-inset-left,  0px), 0px);
  padding-right: max(env(safe-area-inset-right, 0px), 0px);
}

/* ── Global responsive shell padding ────────────────────────── */
@media (max-width: 400px) {
  .system-shell,
  .habits-shell,
  .life-shell,
  .ai-shell,
  .ach-shell,
  .notif-shell {
    padding-left: 12px !important;
    padding-right: 12px !important;
  }
}

/* ── Utility: prevent long words overflowing containers ──────────── */
/* Applied broadly, but overridden per-component for badge/tag elements */
p, h1, h2, h3, h4, h5, h6, a, label {
  overflow-wrap: break-word;
  word-break: break-word;
}
/* Spans only break words when they're NOT tags/badges (component CSS overrides) */
span {
  overflow-wrap: break-word;
}

/* ── Reduced-motion: respect user preference ────────────────── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: .001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: .001ms !important;
  }
  .card-3d:hover { transform: none; }
}

/* ============================================================
   THE SYSTEM — Solo Leveling Life OS · Premium 3D Theme v4
   Foundation: design tokens + container queries + spacing scale.
   ============================================================ */
@use '@angular/material' as mat;
@import '@angular/cdk/overlay-prebuilt.css';

/* ── Google Fonts ─────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Rajdhani:wght@400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap');

:root {
  /* ── Backgrounds ────────────────────────────────────────── */
  --bg-primary:   #05050d;
  --bg-secondary: #0a0a18;
  --card-bg:      #10101e;
  --border:       #1c1c34;
  --border-glow:  #2b2b52;

  /* ── Accents ────────────────────────────────────────────── */
  --accent-purple:     #6C63FF;
  --accent-purple-2:   #534AB7;
  --accent-purple-dim: rgba(108,99,255,0.18);
  --accent-teal:   #1FBE8E;
  --accent-gold:   #FAC775;
  --accent-red:    #E24B4A;
  --accent-cyan:   #4fc3f7;

  /* ── Text ───────────────────────────────────────────────── */
  --text-primary:   #EEF3FA;
  --text-secondary: #7a8494;
  --text-dim:       #3a4050;

  /* ── Stat colors ────────────────────────────────────────── */
  --stat-str: #FF6B3D;
  --stat-int: #6C63FF;
  --stat-vit: #1FBE8E;
  --stat-agi: #FFB020;
  --stat-per: #3B9BFF;
  --stat-hor: #FF5252;

  --system-blue: #4fc3f7;
  --system-glow: rgba(108,99,255,0.60);

  /* ── HP colors ──────────────────────────────────────────── */
  --hp-high: #1FBE8E;
  --hp-mid:  #FAC775;
  --hp-low:  #E24B4A;

  /* ── Spacing scale ──────────────────────────────────────── */
  --s-1:  4px;
  --s-2:  8px;
  --s-3: 12px;
  --s-4: 16px;
  --s-5: 20px;
  --s-6: 24px;
  --s-8: 32px;
  --s-10: 40px;

  /* ── Mobile navigation ──────────────────────────────────── */
  /* Bottom nav bar height + safe-area-inset-bottom */
  --bottom-nav-height: 70px;
  --bottom-nav-total: calc(var(--bottom-nav-height) + env(safe-area-inset-bottom, 0px));

  /* ── Border radius scale ────────────────────────────────── */
  --r-sm:   6px;
  --r-md:  10px;
  --r-lg:  16px;
  --r-xl:  20px;
  --r-pill: 999px;

  /* ── Typography scale ───────────────────────────────────── */
  --fs-2xs: 0.5rem;
  --fs-xs:  0.62rem;
  --fs-sm:  0.72rem;
  --fs-md:  0.86rem;
  --fs-lg:  1rem;
  --fs-xl:  1.2rem;

  /* ── 3D depth / elevation tokens ───────────────────────── */
  --elev-1:
    0 1px 2px rgba(0,0,0,0.40),
    0 2px 8px rgba(0,0,0,0.35);
  --elev-2:
    0 2px 4px rgba(0,0,0,0.45),
    0 8px 20px rgba(0,0,0,0.45),
    0 0 0 1px rgba(255,255,255,0.02) inset;
  --elev-3:
    0 4px 8px rgba(0,0,0,0.50),
    0 16px 40px rgba(0,0,0,0.55),
    0 0 32px rgba(108,99,255,0.10),
    0 1px 0 rgba(255,255,255,0.05) inset;
  --elev-float:
    0 24px 60px rgba(0,0,0,0.60),
    0 8px 24px rgba(108,99,255,0.22),
    0 1px 0 rgba(255,255,255,0.07) inset;

  /* ── Glass surface ──────────────────────────────────────── */
  --glass-fill: linear-gradient(160deg, rgba(24,24,44,0.72), rgba(12,12,26,0.78));
  --glass-blur: 16px;

  /* ── Motion ─────────────────────────────────────────────── */
  --ease-spring: cubic-bezier(.22,1,.36,1);
  --duration-fast:   150ms;
  --duration-normal: 280ms;
  --duration-slow:   420ms;
}

* { box-sizing: border-box; }
html, body { height: 100%; margin: 0; padding: 0; }

/* Enable GPU-accelerated 3D across the app — perspective on html causes
   backdrop-filter blur artefacts on nested elements, so we apply it only
   per-element where needed (see .card-3d hover in styles below). */
/* html { perspective: 1400px; } ← intentionally removed */

/* ── Mobile-first responsive foundations ─────────────────────── */
html {
  font-size: clamp(14px, 1.5vw + 10px, 16px);
  -webkit-text-size-adjust: 100%;
  text-size-adjust: 100%;
}

/* ── Touch targets — only on primary interactive elements ──── */
/* Avoids forcing 44px on tiny UI micro-buttons (handled per-component) */
a[href], [role='button']:not([class*="mini"]):not([class*="tog"]):not([class*="gear"]):not([class*="cls"]) {
  min-height: 44px;
  min-width: 44px;
  touch-action: manipulation;
}
button { touch-action: manipulation; }
.nav a { min-width: unset; min-height: unset; padding: 8px 6px; }

body {
  background:
    radial-gradient(ellipse 1400px 720px at 28% -8%,  rgba(108,99,255,0.24), transparent 60%),
    radial-gradient(ellipse 1100px 620px at 82% 112%, rgba(31,190,142,0.14), transparent 55%),
    radial-gradient(ellipse 640px 440px at 96% 4%,    rgba(79,195,247,0.10), transparent 50%),
    var(--bg-primary);
  color: var(--text-primary);
  font-family: 'Inter', sans-serif;
  min-height: 100vh;
  overflow-x: hidden;
}

/* ── Animated aurora / nebula layer (adds living depth) ──────── */
body::before {
  content: '';
  position: fixed;
  inset: -20%;
  background:
    radial-gradient(closest-side, rgba(108,99,255,0.16), transparent 70%) 20% 30% / 55% 55% no-repeat,
    radial-gradient(closest-side, rgba(31,190,142,0.12), transparent 70%) 80% 70% / 50% 50% no-repeat,
    radial-gradient(closest-side, rgba(79,195,247,0.10), transparent 70%) 60% 15% / 45% 45% no-repeat;
  filter: blur(30px);
  pointer-events: none;
  z-index: 0;
  animation: aurora 26s ease-in-out infinite alternate;
}

@keyframes aurora {
  0%   { transform: translate3d(0,0,0) scale(1);        opacity: .85; }
  50%  { transform: translate3d(3%, -2%, 0) scale(1.08); opacity: 1; }
  100% { transform: translate3d(-2%, 2%, 0) scale(1.04); opacity: .8; }
}

/* ── Star / particle field ───────────────────────────────────── */
body::after {
  content: '';
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(1px 1px at 8%  15%, rgba(255,255,255,0.50), transparent),
    radial-gradient(1px 1px at 22% 55%, rgba(79,195,247,0.45), transparent),
    radial-gradient(1px 1px at 38% 28%, rgba(255,255,255,0.30), transparent),
    radial-gradient(1px 1px at 55% 72%, rgba(108,99,255,0.50), transparent),
    radial-gradient(1px 1px at 72% 42%, rgba(255,255,255,0.35), transparent),
    radial-gradient(2px 2px at 85% 18%, rgba(250,199,117,0.30), transparent),
    radial-gradient(1px 1px at 93% 78%, rgba(31,190,142,0.40), transparent),
    radial-gradient(1px 1px at 15% 88%, rgba(255,255,255,0.25), transparent),
    radial-gradient(1px 1px at 64% 8%,  rgba(79,195,247,0.30), transparent),
    radial-gradient(2px 2px at 48% 96%, rgba(108,99,255,0.25), transparent);
  background-size: 600px 600px;
  opacity: 0.55;
  pointer-events: none;
  z-index: 0;
  animation: drift 80s linear infinite;
}

@keyframes drift {
  from { background-position: 0 0; }
  to   { background-position: 600px 600px; }
}

/* ── Typography ───────────────────────────────────────────── */
.mono  { font-family: 'Orbitron', 'Courier New', monospace; }
.tech  { font-family: 'Rajdhani', sans-serif; letter-spacing: .5px; }

/* Shared desktop top navigation. Several feature pages own their headers, so
   keep the base nav behavior global and let pages only tune colors/spacing. */
.topbar .nav,
.topbar .desktop-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: clamp(12px, 1.4vw, 20px);
  flex-wrap: wrap;
}
.topbar .nav a,
.topbar .desktop-nav a,
.bottom-nav a {
  white-space: nowrap;
  word-break: normal;
  overflow-wrap: normal;
  text-decoration: none;
}
.topbar .nav a {
  color: var(--text-secondary);
  font-size: clamp(.62rem, .78vw, .76rem);
  letter-spacing: 2px;
  font-weight: 700;
}
.topbar .nav a:hover,
.topbar .nav a.active {
  color: var(--text-primary);
}

/* ── Scrollbar ─────────────────────────────────────────────── */
::-webkit-scrollbar { width: 9px; height: 9px; }
::-webkit-scrollbar-track { background: var(--bg-secondary); }
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, #6C63FF, #2a2670);
  border-radius: 6px;
  border: 2px solid var(--bg-secondary);
}
::-webkit-scrollbar-thumb:hover { background: linear-gradient(180deg, #8b83ff, #3a34a0); }

/* ============================================================
   3D SYSTEM CARD — glassmorphic surface with real depth
   container-type: inline-size enables @container queries in
   child components so they adapt to the card's own width, not
   the viewport — this is the key to rock-solid responsive UX.
   ============================================================ */
.system-card {
  background: var(--glass-fill);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  position: relative;
  padding: clamp(var(--s-3), 3vw, var(--s-5));
  backdrop-filter: blur(var(--glass-blur));
  -webkit-backdrop-filter: blur(var(--glass-blur));
  box-shadow: var(--elev-2);
  /* Container query foundation — child CSS can use @container */
  container-type: inline-size;
  container-name: card;
  transition:
    transform  var(--duration-normal) var(--ease-spring),
    box-shadow var(--duration-normal) var(--ease-spring),
    border-color var(--duration-fast);
}
/* Gradient rim-light border */
.system-card::after {
  content: '';
  position: absolute; inset: 0;
  border-radius: var(--r-xl);
  padding: 1px;
  background: linear-gradient(135deg, rgba(108,99,255,0.65), transparent 40%, rgba(79,195,247,0.35));
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}
/* Top specular highlight */
.system-card::before {
  content: '';
  position: absolute; inset: 0 0 auto 0;
  height: 42%;
  border-radius: var(--r-xl) var(--r-xl) 40% 40% / var(--r-xl) var(--r-xl) 100% 100%;
  background: linear-gradient(180deg, rgba(255,255,255,0.06), transparent);
  pointer-events: none;
}
.system-card:hover {
  border-color: rgba(108,99,255,0.45);
  box-shadow: var(--elev-3);
  transform: translateY(-2px);
}

/* Opt-in interactive 3D tilt/lift */
.card-3d {
  transition: transform .35s var(--ease-spring), box-shadow .35s var(--ease-spring);
  will-change: transform;
}
.card-3d:hover {
  transform: perspective(900px) rotateX(2deg) rotateY(-2deg) translateY(-3px) scale(1.01);
  box-shadow: var(--elev-float);
}
.card-3d:active { transform: perspective(900px) translateY(-1px) scale(.997); }

/* ── Premium 3D buttons ──────────────────────────────────────
   Use class="btn-3d" for primary actions. */
.btn-3d {
  position: relative;
  border: 1px solid rgba(108,99,255,0.45);
  border-radius: 12px;
  background: linear-gradient(180deg, #6C63FF, #4a42b0);
  color: #fff;
  font-family: 'Rajdhani', sans-serif;
  font-weight: 700;
  letter-spacing: 1.5px;
  cursor: pointer;
  box-shadow:
    0 6px 0 #322b7a,
    0 10px 22px rgba(108,99,255,0.40),
    0 1px 0 rgba(255,255,255,0.30) inset;
  transition: transform .12s ease, box-shadow .12s ease, filter .2s;
}
.btn-3d:hover { filter: brightness(1.08); }
.btn-3d:active {
  transform: translateY(4px);
  box-shadow:
    0 2px 0 #322b7a,
    0 4px 10px rgba(108,99,255,0.35),
    0 1px 0 rgba(255,255,255,0.25) inset;
}

/* ── Glow utilities ───────────────────────────────────────── */
.glow-text  { text-shadow: 0 0 18px var(--system-glow), 0 0 36px var(--system-glow); }
.glow-teal  { text-shadow: 0 0 12px rgba(31,190,142,0.8); }
.glow-gold  { text-shadow: 0 0 12px rgba(250,199,117,0.7); }

/* XP/progress shimmer utility */
@keyframes shimmer {
  0%,60% { transform: translateX(-100%); }
  100%   { transform: translateX(300%); }
}

/* ── Angular Material dark theme ──────────────────────────── */
$sys-primary: mat.define-palette(mat.$indigo-palette, 400);
$sys-accent:  mat.define-palette(mat.$teal-palette,   400);
$sys-warn:    mat.define-palette(mat.$red-palette);
$sys-theme: mat.define-dark-theme((
  color: (primary: $sys-primary, accent: $sys-accent, warn: $sys-warn),
  typography: mat.define-typography-config(),
  density: 0,
));
@include mat.core();
@include mat.all-component-themes($sys-theme);

/* ── System Snackbar ──────────────────────────────────────── */
@keyframes systemSnackPulse {
  0% { box-shadow: 0 0 15px rgba(31,190,142,0.6), inset 0 0 10px rgba(31,190,142,0.2); border-color: rgba(31,190,142, 0.8); }
  50% { box-shadow: 0 0 35px rgba(31,190,142,0.9), inset 0 0 20px rgba(31,190,142,0.4); border-color: rgba(31,190,142, 1); }
  100% { box-shadow: 0 0 15px rgba(31,190,142,0.6), inset 0 0 10px rgba(31,190,142,0.2); border-color: rgba(31,190,142, 0.8); }
}

.mat-mdc-snack-bar-container.system-snack {
  --mdc-snackbar-container-color:       rgba(10, 10, 24, 0.95);
  --mdc-snackbar-supporting-text-color: #EEF3FA;
  --mat-snack-bar-button-color:         #FAC775;
}
.mat-mdc-snack-bar-container.system-snack .mdc-snackbar__surface {
  border: 1px solid var(--accent-teal);
  border-radius: 12px;
  background: linear-gradient(135deg, rgba(10, 10, 24, 0.95), rgba(31, 190, 142, 0.15));
  backdrop-filter: blur(10px);
  animation: systemSnackPulse 2s infinite ease-in-out;
  font-family: 'Orbitron', sans-serif;
  letter-spacing: 1px;
}
.mat-mdc-snack-bar-container.system-snack-warn .mdc-snackbar__surface {
  border: 1px solid #E24B4A;
  background: linear-gradient(135deg, rgba(10, 10, 24, 0.95), rgba(226, 75, 74, 0.15));
  box-shadow: 0 0 28px rgba(226,75,74,0.65), inset 0 0 12px rgba(226,75,74,0.2);
  font-family: 'Orbitron', sans-serif;
}

/* ── Overlay backdrop ─────────────────────────────────────── */
.cdk-overlay-dark-backdrop {
  background: rgba(3,3,10,0.92);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}
/* Ensure the CDK overlay sits above the bottom navigation bar on mobile */
.cdk-overlay-container {
  z-index: 1000;
}

/* ── Holographic flicker animation ──────────────────────────── */
@keyframes holoBlink {
  0%,100% { opacity: 1; }
  92%     { opacity: 1; }
  93%     { opacity: 0.7; }
  94%     { opacity: 1; }
  96%     { opacity: 0.85; }
  97%     { opacity: 1; }
}

/* ── Stat increase pop ─────────────────────────────────────── */
@keyframes statPop {
  0%   { transform: scale(1); }
  40%  { transform: scale(1.22); filter: brightness(1.8); }
  70%  { transform: scale(0.96); }
  100% { transform: scale(1); filter: brightness(1); }
}
.stat-pop { animation: statPop .55s var(--ease-spring) both; }

/* ── HP danger pulse ─────────────────────────────────────────── */
@keyframes dangerPulse {
  0%,100% { box-shadow: 0 0 8px rgba(226,75,74,0.4); }
  50%     { box-shadow: 0 0 28px rgba(226,75,74,0.9); }
}
.hp-danger { animation: dangerPulse 1.6s ease-in-out infinite; }

/* ── Level-up dialog — full-screen centered overlay ─────────── */
/* The CDK overlay container is already position:fixed full-screen.
   We just need to ensure our custom panel class strips Material's
   padding and that the surface is transparent so our card shows. */
.level-up-panel {
  /* Override Material's default max-width on mobile */
  max-width: calc(100vw - 24px) !important;
}
.level-up-panel .mat-mdc-dialog-container {
  background: transparent;
  box-shadow: none;
  /* Ensure container doesn't add its own padding that shifts alignment */
  padding: 0;
}
.level-up-panel .mat-mdc-dialog-surface {
  background: transparent !important;
  box-shadow: none !important;
  overflow: visible;
  padding: 0;
}
/* The CDK overlay pane that wraps the dialog — make sure it's centred */
.cdk-overlay-pane:has(.level-up-panel),
.cdk-global-overlay-wrapper:has(.level-up-panel) {
  display: flex;
  align-items: center;
  justify-content: center;
}

/* ── Android 15 / iOS edge-to-edge safe areas ───────────────── */
/* Applied universally — env() returns 0 on desktop so no visual change there */
.route-host {
  min-height: 100dvh;
}
@media (max-width: 760px) {
  .route-host {
    /* Reserve space at bottom for the fixed bottom nav + device home indicator */
    padding-bottom: var(--bottom-nav-total);
  }
}
/* Extra side/top safe areas only needed on real devices */
body.native-platform .route-host {
  padding-left:  max(env(safe-area-inset-left,  0px), 0px);
  padding-right: max(env(safe-area-inset-right, 0px), 0px);
}

/* ── Global responsive shell padding ────────────────────────── */
@media (max-width: 400px) {
  .system-shell,
  .habits-shell,
  .life-shell,
  .ai-shell,
  .ach-shell,
  .notif-shell {
    padding-left: 12px !important;
    padding-right: 12px !important;
  }
}

/* ── Utility: prevent long words overflowing containers ──────────── */
/* Applied broadly, but overridden per-component for badge/tag elements */
p, h1, h2, h3, h4, h5, h6, a, label {
  overflow-wrap: break-word;
  word-break: break-word;
}
/* Spans only break words when they're NOT tags/badges (component CSS overrides) */
span {
  overflow-wrap: break-word;
}

/* ── Reduced-motion: respect user preference ────────────────── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: .001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: .001ms !important;
  }
  .card-3d:hover { transform: none; }
}

/* ============================================================
   NATIVE (Android WebView) PERFORMANCE MODE  ·  anti-overheat
   ------------------------------------------------------------
   The Capacitor WebView composites continuous `backdrop-filter`
   blur and infinite full-screen animations far less efficiently
   than a desktop browser. Those effects run on the GPU EVERY
   frame even when the screen is idle, which pegs the GPU/CPU and
   makes the phone hot + drains battery.

   On native we therefore drop the most expensive effects and keep
   cheap static equivalents. The desktop/PWA web build is untouched
   and keeps the full premium look. `native-platform` is added to
   <body> by NativeService on Android only.
   ============================================================ */
body.native-platform::before {
  /* Kill the animated, blurred full-screen aurora — keep a cheap static tint. */
  animation: none !important;
  filter: none !important;
  opacity: .45;
}
body.native-platform::after {
  /* Stop the never-ending particle-drift repaint. */
  animation: none !important;
}
body.native-platform .system-card {
  /* backdrop-filter is the single most expensive WebView operation; having it
     on every card forces a full-screen GPU composite constantly. Replace it
     with an opaque gradient that looks nearly identical but costs nothing. */
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  background: linear-gradient(160deg, rgba(22,22,42,0.98), rgba(12,12,26,0.99));
}
body.native-platform .mat-mdc-snack-bar-container.system-snack .mdc-snackbar__surface {
  animation: none !important;                 /* stop the 2s infinite pulse + its big box-shadow */
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}
body.native-platform .cdk-overlay-dark-backdrop {
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  background: rgba(3,3,10,0.96);
}
/* Safety net: on native, no decorative animation should loop forever while the
   Hunter is just reading the screen. Cap infinite loops to a single play so the
   GPU can go idle. Loading spinners opt back in via `.sys-spin` (keeps looping). */
body.native-platform *:not(.sys-spin),
body.native-platform *:not(.sys-spin)::before,
body.native-platform *:not(.sys-spin)::after {
  animation-iteration-count: 1 !important;
}

:host { display: block; position: relative; z-index: 1; }

/* HP Danger Banner */
.hp-danger-banner {
  position: sticky; top: 0; z-index: 30;
  background: linear-gradient(90deg, rgba(226,75,74,0.18), rgba(226,75,74,0.08));
  border-bottom: 1px solid rgba(226,75,74,0.35);
  padding: clamp(6px, 2vw, 10px) clamp(12px, 4vw, 24px); font-size: clamp(.6rem, 1.8vw, .72rem); letter-spacing: 2px;
  color: #f09595; display: flex; align-items: center; gap: 10px;
  animation: dangerPulse 2s ease-in-out infinite;
}
.hp-danger-banner .mono { font-size: 1.1rem; }

.system-shell { max-width: 1440px; margin: 0 auto; padding: 0 clamp(12px, 4vw, 20px) 80px; }

.topbar {
  display: flex; align-items: center; justify-content: space-between; gap: 14px;
  padding: clamp(8px, 2vw, 12px) clamp(12px, 3vw, 20px); margin-bottom: 22px; flex-wrap: wrap;
  border: 1px solid var(--border); border-top: none; border-radius: 0 0 20px 20px;
  background: linear-gradient(160deg, rgba(22,22,42,0.82), rgba(10,10,26,0.88));
  backdrop-filter: blur(18px); -webkit-backdrop-filter: blur(18px);
  box-shadow: 0 10px 30px rgba(0,0,0,0.45), 0 0 24px rgba(108,99,255,0.10), 0 1px 0 rgba(255,255,255,0.05) inset;
  position: sticky; top: 0; z-index: 20;
}
/* Neon underline that anchors the floating topbar */
.topbar::after {
  content: ''; position: absolute; left: 8%; right: 8%; bottom: -1px; height: 1px;
  background: linear-gradient(90deg, transparent, rgba(108,99,255,0.7), rgba(79,195,247,0.5), transparent);
}
.brand { display: flex; align-items: center; gap: 10px; }
.brand-logo {
  width: 34px; height: 34px;
  filter: drop-shadow(0 0 12px var(--system-blue)) drop-shadow(0 4px 6px rgba(0,0,0,0.5));
  animation: floatLogo 5s ease-in-out infinite;
}
@keyframes floatLogo {
  0%,100% { transform: translateY(0) rotateY(0deg); }
  50%     { transform: translateY(-5px) rotateY(18deg); }
}
.name { font-weight: 900; letter-spacing: 5px; font-size: clamp(.8rem, 2.5vw, 1.05rem); }
.rank-badge-mini {
  font-size: .6rem; letter-spacing: 2px; padding: 3px 8px; border-radius: 6px;
  border: 1px solid rgba(83,74,183,0.4); color: #b3aef0; background: rgba(83,74,183,0.12);
}

.nav { display: flex; gap: 18px; align-items: center; flex-wrap: wrap; }
.nav a {
  color: var(--text-secondary); text-decoration: none; font-size: clamp(.62rem, 1.8vw, .72rem);
  letter-spacing: 2px; font-weight: 600; padding: 8px 6px; position: relative; transition: color .2s;
  min-height: unset;
}
.nav a:hover, .nav a.active { color: var(--text-primary); }
.nav a.active::after {
  content: ''; position: absolute; left: 0; right: 0; bottom: -4px; height: 2px;
  background: linear-gradient(90deg, var(--system-blue), var(--accent-purple)); border-radius: 2px;
}
.nav a.bell { position: relative; font-size: 1rem; }
.nav a.bell .badge {
  position: absolute; top: -8px; right: -12px; min-width: 16px; height: 16px;
  padding: 0 4px; border-radius: 9px; background: #E24B4A; color: #fff;
  font-size: .56rem; font-weight: 800; display: flex; align-items: center; justify-content: center;
  box-shadow: 0 0 12px rgba(226,75,74,0.8); animation: bellPulse 2s ease-in-out infinite;
}
@keyframes bellPulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.22); } }
.gear {
  background: none; border: 1px solid var(--border); border-radius: 7px;
  color: var(--text-secondary); cursor: pointer; padding: 4px 8px;
  font-size: .9rem; transition: all .2s;
}
.gear:hover { color: var(--accent-gold); border-color: var(--accent-gold); }

/* Real-time link indicator */
.live-link {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: .54rem; letter-spacing: 2px; font-weight: 700;
  padding: 3px 8px; border-radius: 20px;
  border: 1px solid rgba(226,75,74,0.35); color: #f09595;
  background: rgba(226,75,74,0.06); transition: all .3s;
}
.live-link .dot {
  width: 6px; height: 6px; border-radius: 50%; background: #E24B4A;
  box-shadow: 0 0 6px rgba(226,75,74,0.8);
}
.live-link.on {
  border-color: rgba(29,158,117,0.45); color: #5dcaa5; background: rgba(29,158,117,0.08);
}
.live-link.on .dot {
  background: #1D9E75; box-shadow: 0 0 8px rgba(29,158,117,0.9);
  animation: livePulse 1.8s ease-in-out infinite;
}
@keyframes livePulse { 0%,100% { opacity: 1; transform: scale(1); } 50% { opacity: .45; transform: scale(1.3); } }

.user { display: flex; align-items: center; gap: 12px; }
.user-info { display: flex; flex-direction: column; gap: 1px; }
.hunter { font-size: .76rem; letter-spacing: 1px; color: var(--accent-gold); }
.title-tag { font-size: .54rem; letter-spacing: 1.5px; color: #ffe6b0; }
.lv { font-size: .58rem; letter-spacing: 2px; color: var(--text-secondary); }
.logout {
  background: transparent; border: 1px solid var(--border); border-radius: 8px;
  color: var(--text-secondary); padding: 6px 12px; cursor: pointer;
  font-size: .66rem; letter-spacing: 1px; transition: all .2s;
}
.logout:hover { border-color: #E24B4A; color: #F09595; }

/* ── 3-column dashboard — fluid, not fixed ─────────────────────────
   Uses clamp() so columns shrink gracefully on medium screens
   without needing an explicit breakpoint. */
.grid {
  display: grid;
  grid-template-columns: clamp(260px, 25vw, 340px) 1fr clamp(240px, 22vw, 300px);
  gap: clamp(12px, 2vw, 18px);
  align-items: start;
}
.col-left, .col-centre, .col-right { display: flex; flex-direction: column; gap: 18px; }

/* Accountability strip */
.accountability {
  padding: 10px 14px; border-radius: 10px; font-size: .74rem; letter-spacing: 1.5px;
  border: 1px solid rgba(226,75,74,0.25); background: rgba(226,75,74,0.06);
  color: #f09595; display: flex; gap: 8px; align-items: center; flex-wrap: wrap;
}
.all-clear {
  padding: 10px 14px; border-radius: 10px; font-size: .72rem; letter-spacing: 1.5px;
  border: 1px solid rgba(29,158,117,0.35); background: rgba(29,158,117,0.08); color: #5dcaa5;
}

.loader {
  display: flex; flex-direction: column; align-items: center; gap: 16px;
  padding: 100px 0; color: var(--text-secondary);
}
.loader-ring {
  width: 56px; height: 56px; border-radius: 50%;
  border: 3px solid rgba(83,74,183,0.2); border-top-color: var(--system-blue);
  animation: spin .8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
.loader p { letter-spacing: 3px; font-size: .78rem; margin: 0; }
.loader-sub { font-size: .62rem; letter-spacing: 2px; color: var(--text-dim); }
.dots::after { content: ''; animation: dots 1.2s steps(4) infinite; }
@keyframes dots { 0%{content:''} 25%{content:'.'} 50%{content:'..'} 75%{content:'...'} }

.footer {
  text-align: center; margin-top: 32px; padding-top: 18px;
  color: var(--text-secondary); font-size: .66rem; letter-spacing: 4px;
  border-top: 1px solid var(--border);
}

/* ── Large tablet: collapse right col to full width ──────────── */
@media (max-width: 1200px) {
  .grid { grid-template-columns: clamp(240px, 30vw, 320px) 1fr; }
  .col-right { grid-column: 1 / -1; }
}

/* ── Tablet portrait / large phone landscape ─────────────────── */
@media (max-width: 760px) {
  .grid { grid-template-columns: 1fr; }
  .nav { gap: 8px 12px; }
  .name { font-size: .9rem; letter-spacing: 3px; }
}

/* ── Small phone (< 560px) ───────────────────────────────────── */
@media (max-width: 560px) {
  .topbar { flex-direction: column; align-items: flex-start; gap: 8px; padding: 10px 14px; }
  .nav { flex-wrap: wrap; gap: 8px 12px; width: 100%; }
  .user { width: 100%; justify-content: space-between; }
  .hp-danger-banner { font-size: .6rem; letter-spacing: 1px; }
}

/* ── Very small phone (< 380px, e.g. Galaxy A02s) ────────────── */
@media (max-width: 380px) {
  .brand-logo { width: 26px; height: 26px; }
  .name { font-size: .75rem; letter-spacing: 2px; }
  .nav a { font-size: .58rem; letter-spacing: 1px; }
  .rank-badge-mini { display: none; } /* hide on tiny screens to save space */
  .grid { gap: 10px; }
}

